type ToggleSize = NonNullable<VariantProps<typeof toggleVariants>["size"]>;

type ToggleSound =
  | SoundName
  | false
  | {
      off?: SoundName | false;
      on?: SoundName | false;
    };

type ToggleProps = Omit<
  TogglePrimitive.Props,
  "className" | "color" | "prefix" | "suffix"
> &
  VariantProps<typeof toggleVariants> & {
    className?: string;
    prefix?: React.ReactNode;
    sound?: ToggleSound;
    suffix?: React.ReactNode;
  };

const toggleIndicatorSizes = {
  micro: "size-3",
  tiny: "size-3",
  small: "size-3.5",
  medium: "size-4",
  large: "size-4",
} satisfies Record<ToggleSize, string>;

const togglePrefixSlotWidths = {
  micro: "0.75rem",
  tiny: "0.875rem",
  small: "1rem",
  medium: "1rem",
  large: "1rem",
} satisfies Record<ToggleSize, string>;

const toggleAffixGaps = {
  micro: "0.375rem",
  tiny: "0.375rem",
  small: "0.5rem",
  medium: "0.5rem",
  large: "0.5rem",
} satisfies Record<ToggleSize, string>;

function getToggleSound(sound: ToggleSound | undefined, pressed: boolean) {
  if (sound === false) return false;

  if (sound === undefined) {
    return pressed ? "toggle.on" : "toggle.off";
  }

  if (typeof sound === "string") return sound;

  return pressed ? sound.on : sound.off;
}

function CheckIcon({ className }: { className?: string }) {
  return (
    <svg className={className} viewBox="0 0 16 16" fill="none" aria-hidden>
      <path
        d="M3.5 8.5L6.5 11.5L12.5 4.5"
        stroke="currentColor"
        strokeWidth="1.75"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  );
}

function ToggleIndicator({ className }: { className?: string }) {
  return (
    <span
      data-slot="toggle-indicator"
      aria-hidden
      className={cn("grid shrink-0 place-items-center", className)}
    >
      <span className="col-start-1 row-start-1 size-1.5 rounded-full bg-current opacity-45 transition-[opacity,scale] duration-150 group-data-[pressed]/toggle:scale-50 group-data-[pressed]/toggle:opacity-0" />
      <CheckIcon className="col-start-1 row-start-1 size-full scale-50 opacity-0 transition-[opacity,scale] duration-150 group-data-[pressed]/toggle:scale-100 group-data-[pressed]/toggle:opacity-100" />
    </span>
  );
}

function ToggleAffix({
  side,
  show,
  gap,
  width,
  children,
}: {
  side: "prefix" | "suffix";
  show: boolean;
  gap: string;
  width?: string;
  children: React.ReactNode;
}) {
  const isPrefix = side === "prefix";

  return (
    <span
      data-slot={isPrefix ? "toggle-prefix" : "toggle-suffix"}
      data-visible={show ? "" : undefined}
      className={cn(
        "inline-flex shrink-0 items-center justify-center overflow-hidden",
        "transition-[width,max-width,opacity,margin] duration-200 ease-out",
        show ? "opacity-100" : "pointer-events-none opacity-0",
      )}
      style={{
        width: width ? (show ? width : "0px") : undefined,
        maxWidth: width ? undefined : show ? "16rem" : "0px",
        marginRight: isPrefix && show ? gap : 0,
        marginLeft: !isPrefix && show ? gap : 0,
      }}
    >
      <span className="inline-flex shrink-0 items-center justify-center gap-1 whitespace-nowrap">
        {children}
      </span>
    </span>
  );
}

const Toggle = React.forwardRef<HTMLButtonElement, ToggleProps>(function Toggle(
  {
    children,
    className,
    color,
    onPressedChange,
    prefix,
    shape,
    size,
    sound,
    suffix,
    type = "button",
    variant,
    ...props
  },
  ref,
) {
  const resolvedSize = size ?? "medium";
  const hasLabel = Boolean(children);
  const hasPrefix = Boolean(prefix);
  const hasSuffix = Boolean(suffix);
  const showDefaultIndicator = !hasLabel && !hasPrefix && !hasSuffix;
  const showPrefix = hasPrefix || showDefaultIndicator;

  const handlePressedChange = React.useCallback<
    NonNullable<TogglePrimitive.Props["onPressedChange"]>
  >(
    (pressed, eventDetails) => {
      const resolvedSound = getToggleSound(sound, pressed);

      if (resolvedSound) {
        playSound(resolvedSound);
      }

      onPressedChange?.(pressed, eventDetails);
    },
    [onPressedChange, sound],
  );

  return (
    <TogglePrimitive
      ref={ref}
      data-slot="toggle"
      type={type}
      className={cn(
        toggleVariants({
          variant,
          color,
          size: resolvedSize,
          shape,
          className,
        }),
      )}
      onPressedChange={handlePressedChange}
      {...props}
    >
      <ToggleAffix
        side="prefix"
        show={showPrefix}
        gap={hasLabel ? toggleAffixGaps[resolvedSize] : "0px"}
        width={hasPrefix ? undefined : togglePrefixSlotWidths[resolvedSize]}
      >
        {hasPrefix ? (
          prefix
        ) : (
          <ToggleIndicator className={toggleIndicatorSizes[resolvedSize]} />
        )}
      </ToggleAffix>

      {children && (
        <span data-slot="toggle-label" className="inline-flex items-center">
          {children}
        </span>
      )}

      <ToggleAffix
        side="suffix"
        show={hasSuffix}
        gap={hasLabel ? toggleAffixGaps[resolvedSize] : "0px"}
      >
        {suffix}
      </ToggleAffix>
    </TogglePrimitive>
  );
});

export { Toggle, toggleVariants };

export type SoundName =
  | "button.solid"
  | "button.soft"
  | "button.ghost"
  | "button.outline"
  | "button.destructive"
  | "dialog.open"
  | "dialog.close"
  | "drawer.open"
  | "drawer.close"
  | "input.focus"
  | "input.unfocus"
  | "input.clear"
  | "select.open"
  | "select.close"
  | "select.change"
  | "slider.commit"
  | "toggle.on"
  | "toggle.off"
  | "switch.on"
  | "switch.off"
  | "checkbox.check"
  | "checkbox.uncheck"
  | "success"
  | "error";

export const soundVariants = ["soft", "click", "snap", "pop", "thock"] as const;

export type SoundVariant = (typeof soundVariants)[number];

type SoundSettings = {
  enabled: boolean;
  variant: SoundVariant;
  volume: number;
};

const settings: SoundSettings = {
  enabled: true,
  variant: "soft",
  volume: 1,
};

const outputVolumeBoost = 4;

let audioContext: AudioContext | null = null;

function isMobileDevice() {
  if (typeof window === "undefined") return false;

  return (
    window.matchMedia("(pointer: coarse)").matches ||
    (typeof navigator !== "undefined" && navigator.maxTouchPoints > 0)
  );
}

function getAudioContext() {
  if (typeof window === "undefined") return null;

  audioContext ??= new AudioContext();

  return audioContext;
}

function getOutputVolume(volume: number) {
  return Math.max(0, Math.min(volume * outputVolumeBoost, 1));
}

function playTone({
  frequency,
  endFrequency,
  duration,
  volume,
  type = "sine",
  envelope = "pluck",
}: {
  frequency: number;
  endFrequency?: number;
  duration: number;
  volume: number;
  type?: OscillatorType;
  envelope?: "pluck" | "swell" | "reverse";
}) {
  if (!settings.enabled) return;
  if (isMobileDevice()) return;

  const ctx = getAudioContext();
  if (!ctx) return;

  const oscillator = ctx.createOscillator();
  const gain = ctx.createGain();
  const outputVolume = getOutputVolume(volume);

  oscillator.type = type;
  oscillator.frequency.setValueAtTime(frequency, ctx.currentTime);
  if (endFrequency) {
    oscillator.frequency.exponentialRampToValueAtTime(
      endFrequency,
      ctx.currentTime + duration,
    );
  }

  gain.gain.setValueAtTime(0.0001, ctx.currentTime);

  if (envelope === "swell") {
    gain.gain.exponentialRampToValueAtTime(
      outputVolume,
      ctx.currentTime + duration * 0.72,
    );
    gain.gain.exponentialRampToValueAtTime(0.0001, ctx.currentTime + duration);
  } else if (envelope === "reverse") {
    gain.gain.exponentialRampToValueAtTime(
      outputVolume,
      ctx.currentTime + 0.002,
    );
    gain.gain.exponentialRampToValueAtTime(
      outputVolume * 0.38,
      ctx.currentTime + duration * 0.32,
    );
    gain.gain.exponentialRampToValueAtTime(0.0001, ctx.currentTime + duration);
  } else {
    gain.gain.exponentialRampToValueAtTime(
      outputVolume,
      ctx.currentTime + 0.004,
    );
    gain.gain.exponentialRampToValueAtTime(0.0001, ctx.currentTime + duration);
  }

  oscillator.connect(gain);
  gain.connect(ctx.destination);

  oscillator.start(ctx.currentTime);
  oscillator.stop(ctx.currentTime + duration);
}

function blip(frequency: number, volume: number) {
  playTone({
    frequency,
    duration: 0.035,
    volume,
    type: "sine",
  });
}

function playButtonSolidSound() {
  playTone({
    frequency: 420,
    duration: 0.045,
    volume: 0.028 * settings.volume,
    type: "triangle",
